import{_ as s,o as t,c as i,a2 as e}from"./chunks/framework.BRk9mohw.js";const k=JSON.parse('{"title":"Canvas 技能","description":"","frontmatter":{},"headers":[],"relativePath":"skills/canvas.md","filePath":"skills/canvas.md"}'),n={name:"skills/canvas.md"};function l(h,a,o,d,p,c){return t(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="canvas-技能" tabindex="-1">Canvas 技能 <a class="header-anchor" href="#canvas-技能" aria-label="Permalink to &quot;Canvas 技能&quot;">​</a></h1><p>在连接的 OpenClaw 节点（Mac 应用、iOS、Android）上显示 HTML 内容。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>canvas 工具让你可以在任何连接节点的画布视图上呈现 web 内容。非常适合：</p><ul><li>显示游戏、可视化效果、仪表板</li><li>展示生成的 HTML 内容</li><li>交互式演示</li></ul><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><h3 id="架构" tabindex="-1">架构 <a class="header-anchor" href="#架构" aria-label="Permalink to &quot;架构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐     ┌──────────────────┐     ┌─────────────┐</span></span>
<span class="line"><span>│  Canvas Host    │────▶│   Node Bridge    │────▶│  Node App   │</span></span>
<span class="line"><span>│  (HTTP Server)  │     │  (TCP Server)    │     │ (Mac/iOS/   │</span></span>
<span class="line"><span>│  Port 18793     │     │  Port 18790      │     │  Android)   │</span></span>
<span class="line"><span>└─────────────────┘     └──────────────────┘     └─────────────┘</span></span></code></pre></div><ol><li><strong>Canvas Host 服务器</strong>：从 <code>canvasHost.root</code> 目录提供静态 HTML/CSS/JS 文件</li><li><strong>Node Bridge</strong>：向连接的节点传达 canvas URL</li><li><strong>Node 应用</strong>：在 WebView 中呈现内容</li></ol><h3 id="tailscale-集成" tabindex="-1">Tailscale 集成 <a class="header-anchor" href="#tailscale-集成" aria-label="Permalink to &quot;Tailscale 集成&quot;">​</a></h3><p>canvas host 服务器根据 <code>gateway.bind</code> 设置绑定：</p><table tabindex="0"><thead><tr><th>绑定模式</th><th>服务器绑定到</th><th>Canvas URL 使用</th></tr></thead><tbody><tr><td><code>loopback</code></td><td>127.0.0.1</td><td>localhost（仅本地）</td></tr><tr><td><code>lan</code></td><td>LAN 接口</td><td>LAN IP 地址</td></tr><tr><td><code>tailnet</code></td><td>Tailscale 接口</td><td>Tailscale 主机名</td></tr><tr><td><code>auto</code></td><td>最佳可用</td><td>Tailscale &gt; LAN &gt; loopback</td></tr></tbody></table><p><strong>关键洞察：</strong> <code>canvasHostHostForBridge</code> 派生自 <code>bridgeHost</code>。当绑定到 Tailscale 时，节点接收如下 URL：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://&lt;tailscale-hostname&gt;:18793/__openclaw__/canvas/&lt;file&gt;.html</span></span></code></pre></div><p>这就是为什么 localhost URL 不起作用 - 节点从 bridge 接收 Tailscale 主机名！</p><h2 id="操作" tabindex="-1">操作 <a class="header-anchor" href="#操作" aria-label="Permalink to &quot;操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>描述</th></tr></thead><tbody><tr><td><code>present</code></td><td>显示画布，可选目标 URL</td></tr><tr><td><code>hide</code></td><td>隐藏画布</td></tr><tr><td><code>navigate</code></td><td>导航到新 URL</td></tr><tr><td><code>eval</code></td><td>在画布中执行 JavaScript</td></tr><tr><td><code>snapshot</code></td><td>捕获画布截图</td></tr></tbody></table><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>在 <code>~/.openclaw/openclaw.json</code> 中：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;canvasHost&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;port&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">18793</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;root&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/Users/you/clawd/canvas&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;liveReload&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;gateway&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;bind&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;auto&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="热重载" tabindex="-1">热重载 <a class="header-anchor" href="#热重载" aria-label="Permalink to &quot;热重载&quot;">​</a></h3><p>当 <code>liveReload: true</code>（默认）时，canvas host：</p><ul><li>监视根目录中的更改（通过 chokidar）</li><li>向 HTML 文件注入 WebSocket 客户端</li><li>当文件更改时自动重新加载连接的画布</li></ul><p>非常适合开发！</p><h2 id="工作流程" tabindex="-1">工作流程 <a class="header-anchor" href="#工作流程" aria-label="Permalink to &quot;工作流程&quot;">​</a></h2><h3 id="_1-创建-html-内容" tabindex="-1">1. 创建 HTML 内容 <a class="header-anchor" href="#_1-创建-html-内容" aria-label="Permalink to &quot;1. 创建 HTML 内容&quot;">​</a></h3><p>将文件放在 canvas 根目录中（默认 <code>~/clawd/canvas/</code>）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/clawd/canvas/my-game.html</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;HTML&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;!DOCTYPE html&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;html&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;head&gt;&lt;title&gt;My Game&lt;/title&gt;&lt;/head&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;body&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &lt;h1&gt;Hello Canvas!&lt;/h1&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;/body&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;/html&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">HTML</span></span></code></pre></div><h3 id="_2-查找你的-canvas-host-url" tabindex="-1">2. 查找你的 canvas host URL <a class="header-anchor" href="#_2-查找你的-canvas-host-url" aria-label="Permalink to &quot;2. 查找你的 canvas host URL&quot;">​</a></h3><p>检查你的 gateway 绑定方式：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.openclaw/openclaw.json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.gateway.bind&#39;</span></span></code></pre></div><p>然后构造 URL：</p><ul><li><strong>loopback</strong>: <code>http://127.0.0.1:18793/__openclaw__/canvas/&lt;file&gt;.html</code></li><li><strong>lan/tailnet/auto</strong>: <code>http://&lt;hostname&gt;:18793/__openclaw__/canvas/&lt;file&gt;.html</code></li></ul><p>查找你的 Tailscale 主机名：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tailscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.Self.DNSName&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;s/\\.$//&#39;</span></span></code></pre></div><h3 id="_3-查找连接的节点" tabindex="-1">3. 查找连接的节点 <a class="header-anchor" href="#_3-查找连接的节点" aria-label="Permalink to &quot;3. 查找连接的节点&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p>查找具有 canvas 功能的 Mac/iOS/Android 节点。</p><h3 id="_4-呈现内容" tabindex="-1">4. 呈现内容 <a class="header-anchor" href="#_4-呈现内容" aria-label="Permalink to &quot;4. 呈现内容&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>canvas action:present node:&lt;node-id&gt; target:&lt;full-url&gt;</span></span></code></pre></div><p><strong>示例：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>canvas action:present node:mac-63599bc4-b54d-4392-9048-b97abd58343a target:http://peters-mac-studio-1.sheep-coho.ts.net:18793/__openclaw__/canvas/snake.html</span></span></code></pre></div><h3 id="_5-导航、截图或隐藏" tabindex="-1">5. 导航、截图或隐藏 <a class="header-anchor" href="#_5-导航、截图或隐藏" aria-label="Permalink to &quot;5. 导航、截图或隐藏&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>canvas action:navigate node:&lt;node-id&gt; url:&lt;new-url&gt;</span></span>
<span class="line"><span>canvas action:snapshot node:&lt;node-id&gt;</span></span>
<span class="line"><span>canvas action:hide node:&lt;node-id&gt;</span></span></code></pre></div><h2 id="调试" tabindex="-1">调试 <a class="header-anchor" href="#调试" aria-label="Permalink to &quot;调试&quot;">​</a></h2><h3 id="白屏-内容未加载" tabindex="-1">白屏 / 内容未加载 <a class="header-anchor" href="#白屏-内容未加载" aria-label="Permalink to &quot;白屏 / 内容未加载&quot;">​</a></h3><p><strong>原因：</strong> URL 与服务器绑定和节点期望不匹配。</p><p><strong>调试步骤：</strong></p><ol><li>检查服务器绑定：<code>cat ~/.openclaw/openclaw.json | jq &#39;.gateway.bind&#39;</code></li><li>检查 canvas 端口：<code>lsof -i :18793</code></li><li>直接测试 URL：<code>curl http://&lt;hostname&gt;:18793/__openclaw__/canvas/&lt;file&gt;.html</code></li></ol><p><strong>解决方案：</strong> 使用与绑定模式匹配的完整主机名，而不是 localhost。</p><h3 id="node-required-错误" tabindex="-1">&quot;node required&quot; 错误 <a class="header-anchor" href="#node-required-错误" aria-label="Permalink to &quot;&quot;node required&quot; 错误&quot;">​</a></h3><p>始终指定 <code>node:&lt;node-id&gt;</code> 参数。</p><h3 id="node-not-connected-错误" tabindex="-1">&quot;node not connected&quot; 错误 <a class="header-anchor" href="#node-not-connected-错误" aria-label="Permalink to &quot;&quot;node not connected&quot; 错误&quot;">​</a></h3><p>节点离线。使用 <code>openclaw nodes list</code> 查找在线节点。</p><h3 id="内容未更新" tabindex="-1">内容未更新 <a class="header-anchor" href="#内容未更新" aria-label="Permalink to &quot;内容未更新&quot;">​</a></h3><p>如果热重载不工作：</p><ol><li>检查配置中的 <code>liveReload: true</code></li><li>确保文件在 canvas 根目录中</li><li>检查日志中的监视器错误</li></ol><h2 id="url-路径结构" tabindex="-1">URL 路径结构 <a class="header-anchor" href="#url-路径结构" aria-label="Permalink to &quot;URL 路径结构&quot;">​</a></h2><p>canvas host 从 <code>/__openclaw__/canvas/</code> 前缀提供：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://&lt;host&gt;:18793/__openclaw__/canvas/index.html  → ~/clawd/canvas/index.html</span></span>
<span class="line"><span>http://&lt;host&gt;:18793/__openclaw__/canvas/games/snake.html → ~/clawd/canvas/games/snake.html</span></span></code></pre></div><p><code>/__openclaw__/canvas/</code> 前缀由 <code>CANVAS_HOST_PATH</code> 常量定义。</p><h2 id="提示" tabindex="-1">提示 <a class="header-anchor" href="#提示" aria-label="Permalink to &quot;提示&quot;">​</a></h2><ul><li>保持 HTML 自包含（内联 CSS/JS）以获得最佳效果</li><li>使用默认 index.html 作为测试页面（包含桥接诊断）</li><li>画布会持续存在，直到你 <code>hide</code> 它或导航离开</li><li>热重载让开发更快 - 保存就会更新！</li><li>A2UI JSON 推送正在进行中 - 目前使用 HTML 文件</li></ul>`,63)])])}const g=s(n,[["render",l]]);export{k as __pageData,g as default};
